import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, Type } from "@google/genai";
import dns from "dns";

// Enable DNS resolution caching or fallback
dns.setDefaultResultOrder("ipv4first");

const app = express();
const PORT = 3000;

app.use(express.json());

// Initialize Gemini SDK with telemetry header as required by rules
const ai = new GoogleGenAI({
  apiKey: process.env.GEMINI_API_KEY,
  httpOptions: {
    headers: {
      "User-Agent": "aistudio-build",
    },
  },
});

// Endpoint to fetch GitHub repositories for any username
app.get("/api/github/repos", async (req, res) => {
  const { username, token } = req.query;

  if (!username || typeof username !== "string") {
    res.status(400).json({ error: "O nome de usuário do GitHub é obrigatório." });
    return;
  }

  try {
    const headers: Record<string, string> = {
      Accept: "application/vnd.github.v3+json",
      "User-Agent": "GitHub-Sites-Hub-AI-Studio",
    };

    if (token && typeof token === "string" && token.trim() !== "") {
      headers["Authorization"] = `Bearer ${token}`;
    }

    // Fetch up to 100 repositories, sorted by updated
    const githubUrl = `https://api.github.com/users/${encodeURIComponent(username)}/repos?per_page=100&sort=updated`;
    const response = await fetch(githubUrl, { headers });

    if (!response.ok) {
      if (response.status === 404) {
        res.status(404).json({ error: `Usuário do GitHub "${username}" não encontrado.` });
        return;
      }
      if (response.status === 403) {
        res.status(403).json({
          error: "Limite de requisições do GitHub atingido para este IP. Insira um Token de Acesso Pessoal (PAT) nas configurações para continuar ou tente mais tarde.",
        });
        return;
      }
      throw new Error(`GitHub API returned state: ${response.status} ${response.statusText}`);
    }

    const repos = await response.json();
    res.json(repos);
  } catch (error: any) {
    console.error("Erro ao buscar repositórios do GitHub:", error);
    res.status(500).json({ error: error.message || "Falha ao conectar com a API do GitHub." });
  }
});

// Endpoint to fetch raw readme for analysis
app.get("/api/github/readme", async (req, res) => {
  const { owner, repo, defaultBranch } = req.query;

  if (!owner || !repo) {
    res.status(400).json({ error: "Parâmetros 'owner' e 'repo' são obrigatórios." });
    return;
  }

  const branch = (defaultBranch as string) || "main";
  const readmeUrls = [
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/${branch}/README.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/${branch}/readme.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/master/README.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/master/readme.md`,
  ];

  for (const url of readmeUrls) {
    try {
      const resp = await fetch(url);
      if (resp.ok) {
        const text = await resp.text();
        res.json({ readme: text.substring(0, 4000) }); // Limit size to avoid overwhelming context
        return;
      }
    } catch (e) {
      // Continue to next fallback URL
    }
  }

  res.json({ readme: "" });
});

// Endpoint to analyze repository and deployment using Gemini API
app.post("/api/github/analyze", async (req, res) => {
  const { repoName, description, homepage, topics, readme, language } = req.body;

  if (!repoName) {
    res.status(400).json({ error: "O nome do repositório é obrigatório para análise." });
    return;
  }

  try {
    if (!process.env.GEMINI_API_KEY) {
      res.status(500).json({
        error: "Chave de API do Gemini não configurada no servidor. Cadastre-a nas configurações.",
      });
      return;
    }

    const prompt = `Analise as informações do seguinte repositório do GitHub e seu respectivo site anunciado para criar metadados ricos em Português (Brasil) para exibição em um painel central de portfólio.

Repositório: ${repoName}
Descrição fornecida no GitHub: ${description || "Sem descrição"}
URL do Site Deployed: ${homepage || "Sem homepage listada"}
Tópicos/Tags: ${Array.isArray(topics) ? topics.join(", ") : "Nenhum"}
Linguagem Principal: ${language || "Não especificada"}

Conteúdo resumido do README.md do projeto:
${readme || "Nenhum README disponível."}

Instruções:
1. Com base no nome, descrição, tags e README, determine DO QUE SE TRATA o projeto. Crie uma descrição elegante, atrativa e profissional em Português, ideal para um card de portfólio de alta categoria. (Máximo de 3 frases curtas e impactantes).
2. Categorize-o em uma das seguintes categorias padrão ou similar relevante: Portfólio, Landing Page, E-commerce, Dashboard/Painel, Jogo, Utilitário/Ferramenta, Blog, Aplicativo Web, Landing Page Produto, API/Backend.
3. Extraia o stack de tecnologias usadas relevantes (ex: React, Tailwind CSS, TypeScript, Vite, Node.js, CSS3, etc.).
4. Identifique até 3 recursos/destaques principais do projeto (funcionalidades inovadoras ou diferenciais).
5. Sugira até 2 dicas inteligentes de melhoria ou próximo passo para o projeto.
6. Forneça uma nota de portfólio criativa de 50 a 100 baseado na completeza do projeto (quantidade de informações, readme estruturado, etc).`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
      config: {
        systemInstruction: "Você é um especialista em desenvolvimento web, avaliação de UI/UX e escrita técnica. Seu trabalho é analisar repositórios e gerar respostas estruturadas extremamente profissionais e em português.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          required: ["description", "category", "techStack", "highlights", "tips", "portfolioScore"],
          properties: {
            description: {
              type: Type.STRING,
              description: "Nova descrição polida de alta qualidade em português (Brasil) para o card do portfólio.",
            },
            category: {
              type: Type.STRING,
              description: "Categoria ideal do site (ex: Portfólio, E-commerce, Landing Page, Jogo, Utilitário, etc.)",
            },
            techStack: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de tecnologias proeminentes detectadas.",
            },
            highlights: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Até 3 pontos fortes/funcionalidades de destaque do projeto.",
            },
            tips: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Até 2 sugestões inteligentes de melhoria.",
            },
            portfolioScore: {
              type: Type.INTEGER,
              description: "Uma pontuação de 50 a 100 para o projeto com base no nível de documentação e escopo.",
            },
          },
        },
      },
    });

    const parsedData = JSON.parse(response.text?.trim() || "{}");
    res.json(parsedData);
  } catch (error: any) {
    console.error("Erro na análise do Gemini:", error);
    res.status(500).json({ error: error.message || "Falha na análise de IA com o Gemini." });
  }
});

// Configure Vite middleware or static serving
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    // Mount Vite development server as middleware
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    // Serve static files in production
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[Server] rodando com sucesso no endereço http://localhost:${PORT}`);
  });
}

startServer();
